module RefModule(data_out, data_in, load, clk, rst);parameter word_size = 10;
  parameter address_size = 8;
  output reg [address_size-1: 0] 	data_out;
  input 	[address_size-1: 0] 	data_in;
  input 			load, clk, rst;
    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or negedge rst or posedge dbg_halt)
    if (rst == 0) data_out <= 0; else if (load) data_out <= data_in;
endmodule
